  function financeRangeBar(range){const recent1=range.start===financeRecentStart(1)&&range.end===TODAY,recent2=range.start===financeRecentStart(2)&&range.end===TODAY,all=range.start===earliestFinanceDate()&&range.end===TODAY;return `<div class="finance-range-bar"><div><strong>当前日期范围：</strong>${esc(range.start)} 至 ${esc(range.end)}<div class="small">按时间倒序显示，并按月份分段统计。</div></div><div class="property-actions"><button class="smallbtn ${recent1?'primary':''}" onclick="setCleaningFinanceRange('recent1')">最近1个月</button><button class="smallbtn ${recent2?'primary':''}" onclick="setCleaningFinanceRange('recent2')">最近两个月</button><button class="smallbtn ${all?'primary':''}" onclick="setCleaningFinanceRange('all')">展开更早历史</button></div></div>`;}
