  function dedupeBookingsByStay(rows){const by=new Map();(rows||[]).forEach(b=>{if(!b)return;const k=pmsStayMirrorKey(b);if(!by.has(k)){by.set(k,{...b,_merged_count:1});return;}const cur=by.get(k);cur._merged_count=(Number(cur._merged_count)||1)+1;if(!cur.guest&&b.guest)cur.guest=b.guest;if(!cur.platform&&b.platform)cur.platform=b.platform;if(!cur.status&&b.status)cur.status=b.status;if(!cur.summary&&b.summary)cur.summary=b.summary;if(!cur.external_event_uid&&b.external_event_uid)cur.external_event_uid=b.external_event_uid;if(!cur.channel_listing_id&&b.channel_listing_id)cur.channel_listing_id=b.channel_listing_id;});return Array.from(by.values());}
