  function dailyBookingCard(b,date,cls){const room=`<span class="badge">${esc(cleanRoomName(b.room_id))}</span>${propBadge(roomPropId(b.room_id))} ${platformBadge(b.platform)}`;let main='',sub='';if(cls==='checkin'){main=`<strong>${esc(pmsRemainText(date,b.checkout))}</strong>`;sub=`退房：${esc(pmsShortDate(b.checkout))} ｜ 客人：${esc(b.guest||'')}`;}else if(cls==='stay'){main=`<strong>${esc(pmsRemainText(date,b.checkout))}</strong> ｜ 退房：${esc(pmsShortDate(b.checkout))}`;sub=`入住：${esc(pmsShortDate(b.checkin))} ｜ 客人：${esc(b.guest||'')}`;}else{main=`${esc(pmsDateRange(b.checkin,b.checkout))}`;sub=`客人：${esc(b.guest||'')}`;}return `<div class="note-card"><div class="note-title">${room}</div><div class="daily-main-line">${main}</div><div class="daily-sub-line">${sub}</div>${renderRoomDateNotesForWork(date,b.room_id)}</div>`;}
